import React,{useState} from "react";

export default function TextFrom(props) {
    let toUpperCase= () =>{
        console.log("Upper case is clicked")
        let newText= Text.toLowerCase();
        setTxet("newText")
    }
    let toOnchange= (event) =>{
        console.log("clicked on change")
        setTxet(event.target.valve)
    }
    const [Text, setTxet] = useState("Enter Your Text");
  return (
    <>
      <form>
        <div className="container my-3">
            <h1>{props.heading}</h1>
          <div className="form-group">
            <textarea className="form-control" id="myBox" value={Text} onChange={toOnchange} rows="6"></textarea>
          </div>
        <button type="button" className="btn btn-primary" onClick={toUpperCase}>ConvertToUpperCase</button>
        </div>
      </form>
    </>
  );
}
